  return `project-swimlanes-${stableKey.replace(/[^a-zA-Z0-9_-]/g, "-")}`;
};

const ticketCountLabel = (count: number): string => `${count} ${count === 1 ? "ticket" : "tickets"}`;

const runLabel = (status: TicketSummary["runStatus"]): string => {
  switch (status) {
    case "idle":
      return "Idle";
    case "running":
      return "Running";
    case "blocked":
      return "Blocked";
    case "failed":
      return "Failed";
    case "completed":
      return "Codex Done";
    case "cancelled":
      return "Cancelled";
    case "drafting":
      return "Drafting";
    default:
      return "Idle";
  }
};

